export function StructureLayerVLUazExactSvg() {
  return (
    <svg viewBox={VLUAZ_VIEWBOX} className="block h-auto w-full" style={{ overflow: 'visible' }} role="img" aria-label="框架关系层级示意（VLUaz）">
      <title>框架关系层级示意（VLUaz）</title>
      {VLUAZ_ELEMENTS.map((el) => {
        if (el.type === 'rect') {
          return (
            <rect
              key={el.id}
              x={el.x}
              y={el.y}
              width={el.width}
              height={el.height}
              rx={el.rx}
              fill={BOX_FILL}
              stroke={el.stroke ? BOX_STROKE : undefined}
              strokeWidth={el.strokeWidth}
              strokeLinecap="round"
            />
          );
        }
        if (el.type === 'path') {
          return (
            <path
              key={el.id}
              d={el.d}
              transform={`translate(${el.x} ${el.y})`}
              fill={el.stroke ? 'none' : BOX_TEXT}
              stroke={el.stroke ? LINE_STROKE : undefined}
              strokeWidth={el.strokeWidth}
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          );
        }
        return (
          <text
            key={el.id}
            x={el.x + el.width / 2}
            y={el.y + el.height / 2}
            textAnchor={el.textAlign === 'center' ? 'middle' : 'start'}
            dominantBaseline="middle"
            fill={BOX_TEXT}
            fontFamily="Inter, ui-sans-serif, system-ui, sans-serif"
            fontSize={el.fontSize}
            fontWeight={el.fontWeight}
          >
            {el.content}
          </text>
        );
      })}
    </svg>
  );
}
